			if tc.wantErr != nil && !errors.Is(err, tc.wantErr) {
				t.Fatalf("expected %v, got %v", tc.wantErr, err)
			}
		})
	}

	if err := (balanceGuard{}).EnsureSufficient(0, 0); err != nil {
		t.Fatalf("expected zero-value guard to allow no-op cost, got %v", err)
	}
}

